int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    string s;
    cin >> s;
    int n = (int)s.size();
    vector<int> pi(n, 0);
    for (int i = 1; i < n; i++) {
        int j = pi[i - 1];
        while (j > 0 && s[i] != s[j]) j = pi[j - 1];
        if (s[i] == s[j]) j++;
        pi[i] = j;
    }

    vector<int> borders;
    for (int k = pi[n - 1]; k > 0; k = pi[k - 1]) borders.push_back(k);
    reverse(borders.begin(), borders.end());

    cout << borders.size() << "\n";
    for (int i = 0; i < (int)borders.size(); i++) {
        if (i) cout << ' ';
        cout << borders[i];
    }
    cout << "\n";
    return 0;
}

